import { type ControlProps, useControl } from '#registry/default/hooks/use-control.ts';
import { useStableCallback } from '#registry/default/hooks/use-stable-callback.ts';

type Func<TArgs extends any[] = [], TRet = void> = (...val: TArgs) => TRet;
type Predicate<TArgs extends any[] = []> = Func<TArgs, boolean>;

type UseRecordControlProps<T extends Record<string | number, any>, TCtx = void> = ControlProps<T, TCtx>;

const emptyObject = {} as Record<string, any>;
/**
 * A hook to manage the state of a dictionary of items.
 */
export function useRecordControl<T extends Readonly<Record<string | number, any>>, TCtx = void>(
  props: UseRecordControlProps<T, TCtx> = {
    finalValue: emptyObject as T,
  }
) {
  type TKey = keyof T;
  type TValue<TSel extends TKey = TKey> = T[TSel];

  type FinderFn<TSel extends TKey = TKey> = Predicate<[key: TSel, value: TValue<TSel>, dict: T]>;
  type ReplacerFn<TSel extends TKey = TKey> = Func<[value: TValue<TSel>, key: TSel, dict: T], TValue<TSel>>;
  type Finder<TSel extends TKey = TKey> = TSel | FinderFn<TSel>;
  type Replacer<TSel extends TKey = TKey> = TValue<TSel> | ReplacerFn<TSel>;

  const [value, setValue] = useControl<T, TCtx>({ ...props, finalValue: emptyObject as T });

  const effect = useStableCallback((key: TKey, prop: TValue, ctx?: TCtx) => {
    set(key, prop, ctx);
    return () => {
      remove(key, ctx);
    };
  });

  const set = useStableCallback(<TSel extends TKey>(finder: Finder<TSel>, replacer: Replacer<TSel>, ctx?: TCtx) =>
    setValue(current => {
      const key =
        typeof finder === 'function'
          ? (Object.entries(current).find(([k, v]) => finder(k as TSel, v as TValue<TSel>, current))?.[0] as TKey)
          : finder;

      if (key == null) return current;

      const prop = typeof replacer === 'function' ? (replacer as any)(current[key], key, current) : replacer;

      return { ...current, [key]: prop };
    }, ctx)
  );

  const merge = useStableCallback((obj: Partial<T> | ((val: T) => Partial<T>), ctx?: TCtx) =>
    setValue(current => ({ ...current, ...(typeof obj === 'function' ? obj(current) : obj) }), ctx)
  );

  const rename = useStableCallback((oldKey: Finder, newKey: TKey, ctx?: TCtx) =>
    setValue(current => {
      const key =
        typeof oldKey === 'function'
          ? (Object.entries(current).find(([k, v]) => oldKey(k as TKey, v as TValue, current))?.[0] as TKey)
          : oldKey;

      if (key == null || key === newKey) return current;

      const { [key]: prop, ...rest } = current;
      return { ...rest, [newKey]: prop } as T;
    }, ctx)
  );

  const remove = useStableCallback((finder: Finder, ctx?: TCtx) =>
    setValue(current => {
      const key =
        typeof finder === 'function'
          ? (Object.entries(current).find(([k, v]) => finder(k, v as TValue, current))?.[0] as TKey)
          : finder;

      if (key == null) return current;
      const { [key]: _, ...rest } = current;
      return rest as T;
    }, ctx)
  );

  /**
   * Sets the order of the keys in the dictionary.
   * Note that you shouldn't rely on the order of the keys in a dictionary.
   * Consider using a list, or keeping order as a property instead.
   * But it can be useful for testing purposes.
   */
  const setKeyOrders = useStableCallback((keys: TKey[] | ((prev: TKey[]) => TKey[]), ctx?: TCtx) =>
    setValue(current => {
      if (typeof keys === 'function') keys = keys(Object.keys(current) as TKey[]);
      return Object.fromEntries(keys.map(key => [key, current[key]])) as T;
    }, ctx)
  );

  const reorderKey = useStableCallback((ind: number, moveBefore?: number, ctx?: TCtx) =>
    setKeyOrders(prev => {
      const newArr = [...prev];
      const [removed] = newArr.splice(ind, 1);
      if (moveBefore == null) newArr.push(removed);
      else newArr.splice(moveBefore, 0, removed);
      return newArr;
    }, ctx)
  );

  return {
    value,
    setValue,

    /**
     * Sets the key-value to the dictionary. Returns a function to remove the key. Use it in an effect hook.
     *
     * @example
     * const { effect } = useDictionary();
     * useEffect(() => effect(key, value), [effect, key, value]);
     */
    effect,

    set,
    remove,
    rename,
    merge,
    setKeyOrders,
    reorderKey,
  };
}
